try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  questions = JSON.parse(cleaned);
} catch (e) {
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    questions = JSON.parse(jsonMatch[0]);
  } else {
    questions = [];
  }
}

return [{ json: { questions, count: questions.length, source: 'Content Gap Analysis' } }];

// === FUSION MULTI-SOURCE + DEDUPLICATION AVANCÉE ===
const items = $input.all();

let allQuestions = [];

for (const item of items) {
  const questions = item.json.questions || [];
  for (const q of questions) {
    allQuestions.push({
      question: q.question,
      source: q.source || 'Unknown',
      signal: q.signal || '',
      icp_target: q.icp_target || 'ICP 1+2',
      suggested_format: q.suggested_format || 'Article + FAQ',
      urgency: q.urgency || 'medium',
      competitor_gap: q.competitor_gap || null
    });
  }
}

// Déduplication avancée — normalisation + Jaccard simplifié
function normalize(text) {
  return text.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenize(text) {
  return new Set(normalize(text).split(' ').filter(w => w.length > 2));
}

function jaccard(a, b) {
  let inter = 0;
  for (const w of a) { if (b.has(w)) inter++; }
  const union = a.size + b.size - inter;
  return union === 0 ? 0 : inter / union;
}

const unique = [];
for (const q of allQuestions) {
  const tokQ = tokenize(q.question);
  let isDup = false;
  for (const existing of unique) {
    const tokE = tokenize(existing.question);
    if (jaccard(tokQ, tokE) > 0.6) {
      isDup = true;
      // Garder celui avec la meilleure urgency
      const urgencyOrder = { critical: 3, high: 2, medium: 1 };
      if ((urgencyOrder[q.urgency] || 0) > (urgencyOrder[existing.urgency] || 0)) {
        Object.assign(existing, q);
      }
      break;
    }
  }
  if (!isDup) unique.push(q);
}

console.log(`Fusion: ${allQuestions.length} questions → ${unique.length} uniques`);
return unique.map(q => ({ json: q }));

