// Combiner les donnees de la question avec son score ENRICHI
const batchItem = $('Traiter un par un').first().json;
const scoreResponse = $input.first().json;

const content = scoreResponse.choices?.[0]?.message?.content || '{}';
const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let scores;
try {
  scores = JSON.parse(cleaned);
} catch {
  scores = { score_novelty: 3, score_payfit_relevance: 3, score_volume: 3, score_timing: 3 };
}

// Forcer en INTEGER (1-5) pour respecter les contraintes Supabase
const sn = Math.max(1, Math.min(5, Math.round(scores.score_novelty || 3)));
const sr = Math.max(1, Math.min(5, Math.round(scores.score_payfit_relevance || 3)));
const sv = Math.max(1, Math.min(5, Math.round(scores.score_volume || 3)));
const st = Math.max(1, Math.min(5, Math.round(scores.score_timing || 3)));

// score_total est GENERATED dans Supabase, on ne l'envoie PAS
// Mais on le calcule ici pour le check auto_generate
const computed_total = (sn + sr + sv) / 3;
const auto_generate = computed_total >= 4;

return [{
  json: {
    type: 'trend',
    data: {
      question: batchItem.question,
      source: batchItem.source,
      signal: batchItem.signal,
      score_novelty: sn,
      score_payfit_relevance: sr,
      score_volume: sv,
      icp_target: batchItem.icp_target || 'ICP 1+2',
      suggested_format: batchItem.suggested_format || 'Article + FAQ',
      status: 'new'
    },
    metadata: {
      urgency: batchItem.urgency,
      score_timing: st,
      competitor_gap: batchItem.competitor_gap,
      auto_generate: auto_generate
    }
  }
}];
